const value = $json || {};
const normalize = (v) => String(v || '').replace(/\s+/g, ' ').trim();
const titleCase = (v) => normalize(v)
  .split(' ')
  .filter(Boolean)
  .map((part) => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
  .join(' ');

const trace_id = normalize(value.trace_id) || (globalThis.crypto?.randomUUID?.() || 'trace_' + Date.now());
const session_id = normalize(value.session_id) || 'session_' + Date.now();
const source = normalize(value.source || 'chat_widget') || 'chat_widget';
const tenant_id = normalize(value.tenant_id);
const business_type = normalize(value.business_type || 'hotel').toLowerCase() || 'hotel';
const room = normalize(value.room);
const area = normalize(value.area);
const guest_name = titleCase(value.guest_name);
const telefono = normalize(value.telefono).replace(/[^\d+\s]/g, '');
const nome_attivita = normalize(value.nome_attivita || 'Hotel');
const request_text = normalize(value.request_text);
const requested_time = normalize(value.requested_time);
const rawType = normalize(value.request_type).toLowerCase();
const notification_email = normalize(value.notification_email).toLowerCase();
const internal_email = normalize(value.internal_email).toLowerCase();
const billing_email = normalize(value.billing_email).toLowerCase();
const telegram_chat_id = normalize(value.telegram_chat_id);

const inferRequestType = (text) => {
  const t = normalize(text).toLowerCase();
  if (!t) return 'generic_request';
  if (/taxi|cab|transfer/.test(t)) return 'taxi_booking';
  if (/asciugaman|cuscin|copert|lenzuol|sapone|carta igienica|pulizia|rifare la camera/.test(t)) return 'housekeeping';
  if (/tv|televisione|aria condizionata|condizionatore|wifi|wi-fi|frigo|lampad|guast|non funziona|rotto|rotta|manutenzione/.test(t)) return 'maintenance';
  if (/acqua|phon|asciugacapelli|adattatore|ferro da stiro|bollitore/.test(t)) return 'amenities';
  if (/sveglia|wake up|svegliatemi/.test(t)) return 'wakeup_call';
  if (/reception|richiam|chiamatemi|operatore/.test(t)) return 'reception_callback';
  return 'generic_request';
};

const allowedTypes = new Set(['housekeeping', 'maintenance', 'amenities', 'taxi_booking', 'wakeup_call', 'reception_callback', 'generic_request']);
const request_type = allowedTypes.has(rawType) ? rawType : inferRequestType(request_text || rawType);

const internalRecipient = notification_email || internal_email || billing_email || '';

let validation_code = '';
let validation_message = '';
if (!tenant_id) {
  validation_code = 'MISSING_TENANT_ID';
  validation_message = 'Tenant mancante.';
} else if (!request_text) {
  validation_code = 'MISSING_REQUEST_TEXT';
  validation_message = 'Richiesta reception mancante.';
} else if (!telegram_chat_id && !internalRecipient) {
  validation_code = 'MISSING_INTERNAL_NOTIFICATION_CHANNEL';
  validation_message = 'Manca un canale interno per inoltrare la richiesta alla reception.';
}

return [{
  json: {
    ...value,
    tenant_id,
    trace_id,
    session_id,
    source,
    business_type,
    room,
    area,
    guest_name,
    telefono,
    nome_attivita,
    request_type,
    request_text,
    requested_time,
    notification_email,
    internal_email,
    billing_email,
    telegram_chat_id,
    internal_recipient_email: internalRecipient,
    validation_code,
    validation_message,
    is_valid_payload: !validation_code,
  },
}];

const input = $('Normalize & Validate Request').item.json;
const payload = {
  trace_id: input.trace_id,
  session_id: input.session_id,
  tenant_id: input.tenant_id,
  nome_struttura: input.nome_attivita || 'Hotel',
  request_type: input.request_type,
  request_text: input.request_text,
  requested_time: input.requested_time || null,
  room: input.room || null,
  area: input.area || null,
  guest_name: input.guest_name || null,
  telefono: input.telefono || null,
  source: input.source || 'chat_widget',
  internal_email: input.internal_recipient_email || null,
  telegram_chat_id: input.telegram_chat_id || null,
};

const rows = [];
const dedupeBase = input.tenant_id + ':reception_request:' + input.trace_id;
const now = new Date().toISOString();

if (input.telegram_chat_id) {
  rows.push({
    json: {
      tenant_id: input.tenant_id,
      channel: 'telegram_internal_hotel',
      template_key: 'hotel_reception_request_internal',
      related_entity_type: 'reception_request',
      related_entity_id: input.trace_id,
      status: 'pending',
      retry_count: 0,
      max_retries: 5,
      next_retry_at: now,
      trace_id: input.trace_id,
      dedupe_key: dedupeBase + ':telegram_internal_hotel',
      payload,
    },
  });
}

if (input.internal_recipient_email) {
  rows.push({
    json: {
      tenant_id: input.tenant_id,
      channel: 'email_internal_hotel',
      template_key: 'hotel_reception_request_internal',
      related_entity_type: 'reception_request',
      related_entity_id: input.trace_id,
      status: 'pending',
      retry_count: 0,
      max_retries: 5,
      next_retry_at: now,
      trace_id: input.trace_id,
      dedupe_key: dedupeBase + ':email_internal_hotel',
      payload,
    },
  });
}

return rows;

const input = $('Normalize & Validate Request').item.json;
const locationLabel = input.room
  ? 'per la camera ' + input.room
  : input.area
    ? 'per l\'area ' + input.area
    : 'alla reception';

return [{
  json: {
    success: true,
    code: 'RECEPTION_REQUEST_FORWARDED',
    message: 'Richiesta inoltrata alla reception.',
